"use server";

import { createClient } from "@/lib/supabase/server";
import type { PostStatus } from "@/lib/types/db";

export type PostWithAuthor = {
  id: string;
  slug: string;
  status: string;
  primary_locale: string;
  author_id: string;
  updated_at: string;
  profiles: { display_name: string | null } | { display_name: string | null }[] | null;
};

export async function getPostsForAdmin(filters?: { status?: PostStatus }) {
  const supabase = await createClient();
  let query = supabase
    .from("posts")
    .select("id, slug, status, primary_locale, author_id, updated_at, profiles(display_name)")
    .order("updated_at", { ascending: false });

  if (filters?.status) {
    query = query.eq("status", filters.status);
  }

  const { data, error } = await query;
  if (error) throw error;
  return (data ?? []) as PostWithAuthor[];
}

/** Posts for dashboard: all with author for admin, only own for normal users. */
export async function getPostsForDashboard(userId: string, isAdmin: boolean): Promise<PostWithAuthor[]> {
  const supabase = await createClient();
  let query = supabase
    .from("posts")
    .select("id, slug, status, primary_locale, author_id, updated_at, profiles(display_name)")
    .order("updated_at", { ascending: false });

  if (!isAdmin) {
    query = query.eq("author_id", userId);
  }

  const { data, error } = await query;
  if (error) throw error;
  return (data ?? []) as PostWithAuthor[];
}
