import { getAuthUserWithRoles, hasAdminRole } from "@/lib/auth";
import { getTranslations } from "next-intl/server";
import { Link } from "@/lib/navigation";
import { getPostsForDashboard } from "@/lib/data/posts";
import { DashboardBlogs } from "./DashboardBlogs";
import { deletePost } from "../(admin)/admin/posts/actions";

export default async function DashboardPage() {
  const { user, roles } = await getAuthUserWithRoles();
  const isAdmin = hasAdminRole(roles);
  const t = await getTranslations();
  const posts = await getPostsForDashboard(user.id, isAdmin);

  async function handleDelete(postId: string) {
    "use server";
    return deletePost(postId);
  }

  return (
    <div className="max-w-3xl mx-auto py-12 px-4">
      <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
        {t("dashboard.title")}
      </h1>
      <p className="mt-2 text-gray-600 dark:text-gray-400">
        {t("dashboard.welcome", { email: user.email ?? "" })}
      </p>

      <section className="mt-8">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
            {t("dashboard.myBlogs")}
          </h2>
          <Link
            href="/dashboard/posts/new"
            className="px-4 py-2 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 rounded text-sm font-medium"
          >
            {t("dashboard.createBlog")}
          </Link>
        </div>
        <DashboardBlogs
          posts={posts}
          isAdmin={isAdmin}
          currentUserId={user.id}
          deletePostAction={handleDelete}
        />
      </section>

      {isAdmin && (
        <section className="mt-8 p-6 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
            {t("dashboard.adminSectionTitle")}
          </h2>
          <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
            {t("dashboard.adminSectionDescription")}
          </p>
          <ul className="mt-4 space-y-2">
            <li>
              <Link
                href="/admin"
                className="text-blue-600 dark:text-blue-400 hover:underline font-medium"
              >
                → {t("dashboard.goToAdmin")}
              </Link>
            </li>
            <li>
              <Link
                href="/admin/posts"
                className="text-blue-600 dark:text-blue-400 hover:underline"
              >
                → {t("dashboard.managePosts")}
              </Link>
            </li>
            <li>
              <Link
                href="/admin/review-queue"
                className="text-blue-600 dark:text-blue-400 hover:underline"
              >
                → {t("dashboard.reviewQueue")}
              </Link>
            </li>
            <li>
              <Link
                href="/admin/settings"
                className="text-blue-600 dark:text-blue-400 hover:underline"
              >
                → {t("dashboard.settings")}
              </Link>
            </li>
          </ul>
        </section>
      )}

      {!isAdmin && (
        <section className="mt-8 p-6 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
            {t("dashboard.userSectionTitle")}
          </h2>
          <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
            {t("dashboard.userSectionDescription")}
          </p>
          <ul className="mt-4 space-y-2">
            <li>
              <Link
                href="/blog"
                className="text-blue-600 dark:text-blue-400 hover:underline"
              >
                → {t("dashboard.viewBlog")}
              </Link>
            </li>
          </ul>
        </section>
      )}

      <p className="mt-8 text-sm text-gray-500 dark:text-gray-400">
        <Link href="/login" className="underline">
          {t("dashboard.backToLogin")}
        </Link>
      </p>
    </div>
  );
}
